// Format contacts for Lusha Bulk Enrichment API
// Builds the full payload: { contacts: [...], metadata: {} }
const items = $input.all();
let contactIdCounter = 1;

const contacts = items
  .filter(item => item.json.email)
  .map(item => ({
    contactId: String(contactIdCounter++),
    email: item.json.email
  }));

const payload = {
  contacts,
  metadata: {}
};

return [{ json: { contactsPayload: JSON.stringify(payload) } }];

// Flatten enriched results into rows for CSV export
const items = $input.all();
const results = [];

for (const item of items) {
  const d = item.json;
  results.push({
    json: {
      firstName: d.firstName || '',
      lastName: d.lastName || '',
      email: d.primaryEmail || '',
      emailType: d.primaryEmailType || '',
      phone: d.primaryPhone || '',
      phoneType: d.primaryPhoneType || '',
      jobTitle: d.jobTitle || '',
      seniority: d.seniority || '',
      company: d.companyName || '',
      companyDomain: d.companyDomain || '',
      industry: d.companyMainIndustry || '',
      companySize: d.companySize || '',
      revenueRange: d.revenueRange || '',
      location: d.companyLocation || '',
      enrichedAt: new Date().toISOString()
    }
  });
}

return results;
